const payload = $json.body || $json;
const agents = [
  'shift-handoff-generator',
  'predictive-maintenance',
  'safety-compliance-auditor',
  'telemetry-analyzer'
];
if (!payload.agent || !agents.includes(payload.agent)) {
  return { error: 'Unknown or missing agent', available: agents };
}
return { agent: payload.agent, context: payload.context || {}, dispatchedAt: new Date().toISOString() };

const { agent, context } = $json;
const config = {
  'shift-handoff-generator': { model: 'claude-sonnet', maxTokens: 2048 },
  'predictive-maintenance': { model: 'claude-haiku', maxTokens: 1024 },
  'safety-compliance-auditor': { model: 'claude-sonnet', maxTokens: 4096 },
  'telemetry-analyzer': { model: 'claude-haiku', maxTokens: 1024 }
};
return { agent, context, config: config[agent], status: 'executing' };

const { agent, context, config } = $json;
return {
  status: 'completed',
  agent,
  config,
  contextKeys: Object.keys(context),
  result: `Agent ${agent} executed with ${config.model}`,
  completedAt: new Date().toISOString()
};
